// Auto-generated multi-disease dataset — PRISM-H v3 P1
// 21 districts × 36 weeks × 4 levels × 3 diseases (dengue, chikungunya, malaria)
// Period: Sep 7, 2025 → May 10, 2026
//
// Disease patterns:
//   Dengue:      Urban-led (Bengaluru, Khordha, Visakhapatnam top)
//   Chikungunya: Similar urban pattern, ~30% magnitude of dengue
//   Malaria:     Tribal/forested (Sundargarh, Mayurbhanj top); urban very low
//
// Plus: per-district freshness (last_reported, status), epi-week labels.

export interface WardData { name: string; weekly: number[]; }
export interface MunicipalityData { name: string; weekly: number[]; wards: WardData[]; }
export interface VillageData { name: string; weekly: number[]; }
export interface BlockData { name: string; weekly: number[]; villages: VillageData[]; }
export interface DistrictData {
  state: string;
  type: 'metro'|'city'|'coastal'|'industrial'|'rural';
  characteristic: 'rising'|'stable'|'falling'|'emergence'|'chronic';
  weekly_total: number[];
  municipalities: MunicipalityData[];
  blocks: BlockData[];
}

export interface ForecastEntry {
  weeks: number[];
  outbreak_prob: number;
  level: 'low'|'moderate'|'high'|'very_high';
  mu?: number;
  sigma?: number;
}

export interface HierarchyForecast {
  district_forecast: ForecastEntry;
  district_baseline: { mu: number; sigma: number };
  district_level: 'low'|'moderate'|'high'|'very_high';
  municipalities: Record<string, { forecast: ForecastEntry; wards: Record<string, ForecastEntry>; }>;
  blocks: Record<string, { forecast: ForecastEntry; villages: Record<string, ForecastEntry>; }>;
}

export interface FreshnessEntry {
  last_reported: string;
  days_ago: number;
  status: 'fresh'|'good'|'stale'|'concerning';
  message: string;
}

export type DiseaseId = 'dengue' | 'chikungunya' | 'malaria';

